export async function renameThread(
  supabase: DatabaseClient,
  userId: string,
  threadId: string,
  title: string,
) {
  const { error } = await supabase
    .from("chat_threads")
    .update({
      title,
      is_title_autogenerated: false,
      updated_at: new Date().toISOString(),
    })
    .eq("id", threadId)
    .eq("user_id", userId);

  if (error) throw error;
  return getThread(supabase, userId, threadId);
}

export async function updateThreadPinnedState(
  supabase: DatabaseClient,
  userId: string,
  args: { threadId: string; pinned: boolean },
) {
  const { data, error } = await supabase
    .from("chat_threads")
    .update({
      pinned_at: args.pinned ? new Date().toISOString() : null,
      updated_at: new Date().toISOString(),
    })
    .eq("id", args.threadId)
    .eq("user_id", userId)
    .select(threadSelect)
    .single();

  if (error) throw error;
  return castRow<ThreadRecord>(data);
}

export async function updateThreadStatus(
  supabase: DatabaseClient,
  userId: string,
  args: { threadId: string; status: ThreadRecord["status"] },
) {
  const archivedAt = args.status === "archived" ? new Date().toISOString() : null;
  const { data, error } = await supabase
    .from("chat_threads")
    .update({
      status: args.status,
      archived_at: archivedAt,
      updated_at: new Date().toISOString(),
    })
    .eq("id", args.threadId)
    .eq("user_id", userId)
    .select(threadSelect)
    .single();

  if (error) throw error;
  return castRow<ThreadRecord>(data);
}

export async function deleteThread(
  supabase: DatabaseClient,
  userId: string,
  threadId: string,
) {
  const { error } = await supabase
    .from("chat_threads")
    .delete()
    .eq("id", threadId)
    .eq("user_id", userId);

  if (error) throw error;
}
